SELECT * FROM energy_account_balance_consume_record WHERE is_deleted = 0
AND owner_name LIKE CONCAT('%', #{accountNameLike}, '%')
AND consume_time >= #{consumeTimeStart}
AND consume_time <= #{consumeTimeEnd}
ORDER BY consume_time DESC, id DESC

SELECT COUNT(1)
FROM energy_account_balance_consume_record
WHERE is_deleted = 0
  AND consume_type = 0
  AND account_id = #{accountId}
  AND consume_time >= #{monthStart}
  AND consume_time < #{monthEnd}
